### ✅ Nouveau `meta_form.html`

```html
<form id="metaForm">
  <div>
    <label for="metaType">Type de métaschéma :</label>
    <select id="metaType" name="metaType" onchange="generateFields()">
      <option value="">--Choisir--</option>
      <option value="MetaScenario">MetaScenario</option>
      <option value="MetaHookType">MetaHookType</option>
      <!-- Ajoutez d'autres types ici -->
    </select>
  </div>

  <div id="dynamicFields"></div>

  <button type="submit">Envoyer</button>
</form>

<script>
  const schemas = {
    MetaScenario: {
      name: "string",
      description: "string",  // chaîne simple
      steps: "list"           // pas de champ "entrypoint"
    },
    MetaHookType: {
      name: "string",
      category: "string",
      methods: "list"
    }
  };

  function generateFields() {
    const container = document.getElementById("dynamicFields");
    container.innerHTML = "";

    const selected = document.getElementById("metaType").value;
    const fields = schemas[selected];

    if (!fields) return;

    for (const key in fields) {
      const type = fields[key];

      const wrapper = document.createElement("div");
      wrapper.innerHTML = `<label for="${key}">${key} :</label>`;

      if (type === "string") {
        wrapper.innerHTML += `<input type="text" name="${key}" id="${key}"/>`;
      } else if (type === "list") {
        wrapper.innerHTML += `
          <div id="${key}_container">
            <input type="text" name="${key}[]" />
          </div>
          <button type="button" onclick="addListItem('${key}')">+</button>
        `;
      }

      container.appendChild(wrapper);
    }
  }

  function addListItem(field) {
    const container = document.getElementById(`${field}_container`);
    const input = document.createElement("input");
    input.type = "text";
    input.name = `${field}[]`;
    container.appendChild(input);
  }

  document.getElementById("metaForm").addEventListener("submit", function (e) {
    e.preventDefault();
    const form = new FormData(e.target);
    const output = {};
    for (let [key, value] of form.entries()) {
      if (key.endsWith("[]")) {
        const base = key.slice(0, -2);
        output[base] = output[base] || [];
        output[base].push(value);
