### 🛠️ Étapes de mise en place

#### 1. Côté **backend**, exposer les métaschemas

Il faut une route API qui retourne la structure du JSON demandé.

Par exemple :

```python
# app/routes.py
from fastapi import APIRouter
import json
import os

router = APIRouter()

@router.get("/api/schema/{meta_type}")
def get_meta_schema(meta_type: str):
    path = f"metaSchemas/{meta_type}.json"
    if not os.path.exists(path):
        return {"error": "Type inconnu"}
    with open(path, "r", encoding="utf-8") as f:
        return json.load(f)
```

---

#### 2. Côté **frontend (meta_form.html)** : générer dynamiquement le formulaire

On ajoute un script JS qui, lorsqu’un type est sélectionné, **appelle `/api/schema/<type>`** et **construit le formulaire dynamiquement**.

Voici la version *simplifiée* du script :

```html
<script>
async function updateForm() {
  const type = document.getElementById("meta_type").value;
  const container = document.getElementById("form_fields");
  container.innerHTML = ""; // Reset le formulaire

  if (!type) return;

  const res = await fetch(`/api/schema/${type}`);
  const schema = await res.json();

  for (const key in schema) {
    const value = schema[key];

    // On ignore les champs techniques
    if (["type", "metaType"].includes(key)) continue;

    const label = document.createElement("label");
    label.textContent = key.charAt(0).toUpperCase() + key.slice(1);
    container.appendChild(label);

    if (Array.isArray(value)) {
      const div = document.createElement("div");
      div.id = key + "_container";
      const input = document.createElement("input");
      input.placeholder = `${key}...`;
      input.required = true;
      div.appendChild(input);
      container.appendChild(div);

      const addBtn = document.createElement("button");
      addBtn.textContent = "Ajouter";
      addBtn.type = "button";
      addBtn.onclick = () => {
        const newInput = document.createElement("input");
        newInput.placeholder = `${key}...`;
        newInput.required = true;
        div.appendChild(newInput);
        div.appendChild(document.createElement("br"));
      };
      container.appendChild(addBtn);

    } else if (typeof value === "object") {
      // Champ multilingue (FR, EN)
      const textarea = document.createElement("textarea");
      textarea.required = true;
      textarea.placeholder = key + " (FR)";
      textarea.name = key;
      container.appendChild(textarea);

    } else {
      const input = document.createElement("input");
      input.type = "text";
      input.required = true;
      input.name = key;
      container.appendChild(input);
    }
  }
}
</script>
```

