async def route_page(request: Request, page: str = "index"):
    try:
        return templates.TemplateResponse(f"{page}.html", {"request": request})
    except:
        return HTMLResponse(content=f"<h1>Page '{page}.html' not found</h1>", status_code=404)


@router.get("/api")
async def route_api(object: str = None, method: str = None):
    try:
        if object is None or method is None:
            return JSONResponse(status_code=400, content={"error": "Missing object or method"})

        module_path = f"meta.{object}.actions.{method}"
        mod = importlib.import_module(module_path)
        func = getattr(mod, method)
        result = func()
        return JSONResponse(content={"result": result})

    except ModuleNotFoundError as e:
        return JSONResponse(status_code=500, content={"error": f"Module not found: {str(e)}"})
    except AttributeError as e:
        return JSONResponse(status_code=500, content={"error": f"Method not found in module: {str(e)}"})
    except Exception as e:
        return JSONResponse(status_code=500, content={"error": f"Unhandled error: {str(e)}"})
