    object_name = request.query_params.get("object")
    method = request.query_params.get("method")

    if not object_name or not method:
        return JSONResponse(content={"error": "Missing 'object' or 'method' parameter"}, status_code=400)

    try:
        module_path = f"meta.{object_name}.actions.{method}"
        module = import_module(module_path)
    except ModuleNotFoundError:
        return JSONResponse(content={"error": f"Module not found: No module named '{module_path}'"}, status_code=404)
    except Exception as e:
        return JSONResponse(content={"error": f"Error importing module: {str(e)}"}, status_code=500)

