        return JSONResponse(content={"error": f"Method '{method}' not found in module '{module_path}'"}, status_code=404)

    try:
        # Extraire tous les paramètres sauf object et method
        params = {k: v for k, v in request.query_params.items() if k not in ["object", "method"]}
        result = method_func(**params)
