    params = dict(request.query_params)

    object_name = params.get("object")
    method_name = params.get("method")

    if not object_name or not method_name:
        return JSONResponse(content={"error": "Paramètres 'object' et 'method' requis."})

    try:
        method = call("method", method_name)
        if not callable(method):
            return JSONResponse(content={"error": f"{method_name} n'est pas une fonction valide."})
    except Exception as e:
        return JSONResponse(content={"error": f"Impossible de charger la méthode '{method_name}': {str(e)}"})

    try:
        # Exclure les clés 'object' et 'method' du dictionnaire passé à la méthode
        callable_params = {k: v for k, v in params.items() if k not in ["object", "method"]}
        result = method(**callable_params)
        return JSONResponse(content={"result": result})
    except Exception as e:
        return JSONResponse(content={"error": f"Unhandled error: {str(e)}"})
