# :file: enhanced_routes.py
# :type: router
# :description: Gère les routes dynamiques /<page> et /api
# :inputs: object, method, autres paramètres dynamiques
# :outputs: TemplateResponse ou JSON

from fastapi import APIRouter, Request
from fastapi.responses import JSONResponse
from fastapi.templating import Jinja2Templates
from meta.SuperLoader.actions.call import call

router = APIRouter()
templates = Jinja2Templates(directory="templates")


@router.get("/{page}")
async def route_page(request: Request, page: str):
    try:
        return templates.TemplateResponse(f"{page}.html", {"request": request})
    except Exception as e:
        return JSONResponse(content={"error": str(e)}, status_code=500)


@router.get("/api")
async def route_api(request: Request):
    try:
        query = dict(request.query_params)

        object_name = query.get("object")
        method_name = query.get("method")

        if not object_name or not method_name:
            return JSONResponse(
                content={"error": "Les paramètres 'object' et 'method' sont requis"},
                status_code=400,
            )

        obj = call("object", object_name)

        if not hasattr(obj, method_name):
            return JSONResponse(
                content={"error": f"L’objet {object_name} ne contient pas la méthode {method_name}"},
                status_code=400,
            )

        method = getattr(obj, method_name)

        # Extraire uniquement les arguments supplémentaires
        args = {
            k: v for k, v in request.query_params.items()
            if k not in ("object", "method")
        }

        result = method(**args)
        return JSONResponse(content={"result": result})

    except Exception as e:
        return JSONResponse(content={"error": f"Unhandled error: {str(e)}"}, status_code=500)
